51	  Future<void> _load() async {
52	    setState(() { _isLoading = true; _error = null; });
53	    try {
54	      final prefs = await SharedPreferences.getInstance();
55	      final jwtToken = prefs.getString('jwt_token');
56	      final username = prefs.getString('username');
57	
58	      if (jwtToken == null) {
59	        setState(() { _error = 'Not logged in'; _isLoading = false; });
60	        return;
61	      }
62	
