3	import 'package:http/http.dart' as http;
4	import 'package:shared_preferences/shared_preferences.dart';
5	
6	class ApiService {
7	  static String get baseUrl => BaseConfig.baseUrl;
8	  
9	  // Check username availability
10	  static Future<bool> checkUsername(String username) async {
11	    try {
12	      final response = await http.get(
13	        Uri.parse('$baseUrl/api/check-username?username=${Uri.encodeComponent(username)}'),
14	      );
15	      if (response.statusCode == 200) {
16	        return jsonDecode(response.body)['available'] == true;
17	      }
18	      return false;
19	    } catch (e) {
20	      return false;
21	    }
22	  }
23	
24	  // Register user
25	  static Future<bool> register(String username, String password) async {
26	    try {
27	      final response = await http.post(
28	        Uri.parse('$baseUrl/api/register'),
29	        headers: {'Content-Type': 'application/json'},
30	        body: jsonEncode({
31	          'username': username,
32	          'email': '$username@logindemo.com',
33	          'password': password,
34	        }),
35	      );
36	      return response.statusCode == 201;
37	    } catch (e) {
38	      return false;
39	    }
40	  }
41	  
42	  // Login user
43	  static Future<Map<String, dynamic>> login(String username, String password) async {
44	    try {
45	      final response = await http.post(
46	        Uri.parse('$baseUrl/api/login'),
47	        headers: {
48	          'Content-Type': 'application/x-www-form-urlencoded',
49	        },
50	        body: 'username=${Uri.encodeComponent(username)}&password=${Uri.encodeComponent(password)}',
51	      );
52	      
