import 'package:flutter/material.dart';
import 'dart:async';
import '../services/api_service.dart';
import 'dob_screen.dart';

class RegisterScreen extends StatefulWidget {
  const RegisterScreen({super.key});

  @override
  State<RegisterScreen> createState() => _RegisterScreenState();
}

class _RegisterScreenState extends State<RegisterScreen> {
  final _usernameController = TextEditingController();
  final _passwordController = TextEditingController();

  String _usernameError = '';
  String _passwordError = '';
  String _generalError = '';
  bool _usernameAvailable = false;
  bool _checkingUsername = false;
  bool _isLoading = false;

  Timer? _debounce;

  @override
  void dispose() {
    _debounce?.cancel();
    _usernameController.dispose();
    _passwordController.dispose();
    super.dispose();
  }

  void _onUsernameChanged(String value) {
    if (_debounce?.isActive ?? false) _debounce!.cancel();
    setState(() { _usernameAvailable = false; _usernameError = ''; });
    if (value.trim().length < 3) {
      setState(() => _usernameError = value.isEmpty ? '' : 'At least 3 characters');
      return;
    }
    setState(() => _checkingUsername = true);
    _debounce = Timer(const Duration(milliseconds: 600), () async {
      final available = await ApiService.checkUsername(value.trim());
      if (mounted) {
        setState(() {
          _checkingUsername = false;
          _usernameAvailable = available;
          _usernameError = available ? '' : 'Username already taken';
        });
      }
    });
  }

  void _onPasswordChanged(String value) {
    setState(() {
      _passwordError = (value.isNotEmpty && value.length < 12)
          ? 'Minimum 12 characters'
          : '';
    });
  }

  void _next() {
    final username = _usernameController.text.trim();
    final password = _passwordController.text;

    if (username.isEmpty || password.isEmpty) {
      setState(() => _generalError = 'Please fill in all fields');
      return;
    }
    if (!_usernameAvailable) {
      setState(() => _usernameError = 'Choose an available username');
      return;
    }
    if (password.length < 12) {
      setState(() => _passwordError = 'Minimum 12 characters');
      return;
    }

    if (mounted) {
      Navigator.of(context).push(
        MaterialPageRoute(
          builder: (_) => DobScreen(username: username, password: password),
        ),
      );
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Create Account'),
        leading: const BackButton(color: Colors.white),
      ),
      body: SafeArea(
        child: Padding(
          padding: const EdgeInsets.all(28.0),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              const Spacer(),
              const Icon(Icons.person_add_outlined, size: 48, color: Colors.blueAccent),
              const SizedBox(height: 20),
              const Text('Create an account',
                  style: TextStyle(fontSize: 26, fontWeight: FontWeight.bold, color: Colors.white)),
              const SizedBox(height: 6),
              const Text('Choose a username and password',
                  style: TextStyle(fontSize: 15, color: Colors.grey)),
              const SizedBox(height: 36),
              TextField(
                controller: _usernameController,
                onChanged: _onUsernameChanged,
                style: const TextStyle(color: Colors.white),
                decoration: InputDecoration(
                  labelText: 'Username',
                  prefixIcon: const Icon(Icons.person_outline),
                  suffixIcon: _checkingUsername
                      ? const Padding(
                          padding: EdgeInsets.all(12),
                          child: SizedBox(width: 18, height: 18,
                              child: CircularProgressIndicator(strokeWidth: 2, color: Colors.blueAccent)))
                      : _usernameController.text.trim().length >= 3
                          ? Icon(
                              _usernameAvailable ? Icons.check_circle : Icons.cancel,
                              color: _usernameAvailable ? Colors.greenAccent : Colors.redAccent,
                            )
                          : null,
                  errorText: _usernameError.isEmpty ? null : _usernameError,
                ),
              ),
              const SizedBox(height: 16),
              TextField(
                controller: _passwordController,
                obscureText: true,
                onChanged: _onPasswordChanged,
                style: const TextStyle(color: Colors.white),
                decoration: InputDecoration(
                  labelText: 'Password',
                  prefixIcon: const Icon(Icons.lock_outline),
                  helperText: 'Minimum 12 characters',
                  helperStyle: const TextStyle(color: Colors.grey),
                  errorText: _passwordError.isEmpty ? null : _passwordError,
                ),
              ),
              const SizedBox(height: 10),
              if (_generalError.isNotEmpty)
                Text(_generalError, style: const TextStyle(color: Colors.redAccent, fontSize: 13)),
              const SizedBox(height: 24),
              SizedBox(
                width: double.infinity,
                child: ElevatedButton(
                  onPressed: _isLoading ? null : _next,
                  child: _isLoading
                      ? const SizedBox(height: 20, width: 20,
                          child: CircularProgressIndicator(color: Colors.white, strokeWidth: 2))
                      : const Text('Continue'),
                ),
              ),
              const Spacer(),
            ],
          ),
        ),
      ),
    );
  }
}

