import 'dart:convert';
import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;
import 'package:shared_preferences/shared_preferences.dart';
import '../core/config.dart';
import 'chat_screen.dart';

class MatchesScreen extends StatefulWidget {
  final ValueNotifier<int>? refreshTick;

  const MatchesScreen({super.key, this.refreshTick});

  @override
  State<MatchesScreen> createState() => _MatchesScreenState();
}

class _MatchesScreenState extends State<MatchesScreen> {
  static const _bg = Color(0xFF0E0E0E);
  static String get _baseUrl => BaseConfig.baseUrl;
  static const _streamApiKey = '67j8nyav75n9';

  bool _isLoading = true;
  String? _error;
  List<Map<String, dynamic>> _matches = [];
  String? _streamToken;
  String? _currentUsername;

  @override
  void initState() {
    super.initState();
    // First load at mount — no reliance on addPostFrameCallback inside build.
    _load();
    widget.refreshTick?.addListener(_onRefreshTick);
  }

  @override
  void dispose() {
    widget.refreshTick?.removeListener(_onRefreshTick);
    super.dispose();
  }

  void _onRefreshTick() {
    _load();
  }

  Future<String?> _getToken() async {
    final prefs = await SharedPreferences.getInstance();
    return prefs.getString('jwt_token');
  }

  Future<void> _load() async {
    setState(() { _isLoading = true; _error = null; });
    try {
      final prefs = await SharedPreferences.getInstance();
      final jwtToken = prefs.getString('jwt_token');
      final username = prefs.getString('username');

      if (jwtToken == null) {
        setState(() { _error = 'Not logged in'; _isLoading = false; });
        return;
      }

      final headers = {'Authorization': 'Bearer $jwtToken'};

      final results = await Future.wait([
        http.get(Uri.parse('$_baseUrl/api/matches'), headers: headers),
        http.get(Uri.parse('$_baseUrl/api/stream-token'), headers: headers),
      ]);

      final matchesRes = results[0];
      final streamRes = results[1];

      if (matchesRes.statusCode != 200) {
        setState(() { _error = 'Failed to load matches (${matchesRes.statusCode})'; _isLoading = false; });
        return;
      }

      final matchesData = jsonDecode(matchesRes.body) as Map<String, dynamic>;
      // API returns {"users": [...]} not {"matches": [...]}
      final matches = (matchesData['users'] as List<dynamic>? ?? []).cast<Map<String, dynamic>>();

      String? streamToken;
      if (streamRes.statusCode == 200) {
        final streamData = jsonDecode(streamRes.body) as Map<String, dynamic>;
        streamToken = streamData['token'] as String?;
      }

      setState(() {
        _matches = matches;
        _streamToken = streamToken;
        _currentUsername = username;
        _isLoading = false;
      });
    } catch (e) {
      setState(() { _error = 'Error: $e'; _isLoading = false; });
    }
  }

  void _openChat(Map<String, dynamic> match) {
    if (_streamToken == null || _currentUsername == null) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Chat unavailable — could not get Stream token')),
      );
      return;
    }
    Navigator.push(
      context,
      MaterialPageRoute(
        builder: (_) => ChatScreen(
          matchUsername: match['username'] as String,
          currentUsername: _currentUsername!,
          streamToken: _streamToken!,
          apiKey: _streamApiKey,
        ),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: _bg,
      appBar: AppBar(
        backgroundColor: _bg,
        elevation: 0,
        centerTitle: true,
        title: const Column(
          children: [
            Text(
              'MATCHES',
              style: TextStyle(
                color: Colors.white,
                fontWeight: FontWeight.bold,
                fontSize: 16,
                letterSpacing: 1.2,
              ),
            ),
            Text(
              'People who like each other',
              style: TextStyle(color: Colors.white38, fontSize: 11),
            ),
          ],
        ),
        actions: [
          IconButton(
            icon: const Icon(Icons.refresh, color: Colors.white54),
            onPressed: _load,
          ),
        ],
      ),
      body: _buildBody(),
    );
  }

  Widget _buildBody() {
    if (_isLoading) {
      return const Center(child: CircularProgressIndicator(color: Colors.greenAccent));
    }
    if (_error != null) {
      return Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            Text(_error!, style: const TextStyle(color: Colors.redAccent)),
            const SizedBox(height: 16),
            TextButton(onPressed: _load, child: const Text('Retry')),
          ],
        ),
      );
    }
    if (_matches.isEmpty) {
      return RefreshIndicator(
        onRefresh: _load,
        color: Colors.greenAccent,
        child: ListView(
          children: const [
            SizedBox(height: 200),
            Center(
              child: Column(
                children: [
                  Icon(Icons.favorite, size: 64, color: Colors.greenAccent),
                  SizedBox(height: 16),
                  Text('No matches yet', style: TextStyle(color: Colors.white70, fontSize: 16)),
                  SizedBox(height: 8),
                  Text('Keep liking people!', style: TextStyle(color: Colors.white38, fontSize: 13)),
                ],
              ),
            ),
          ],
        ),
      );
    }

    return RefreshIndicator(
      onRefresh: _load,
      color: const Color(0xFF00C853),
      child: ListView.builder(
        padding: const EdgeInsets.only(top: 8, bottom: 80),
        itemCount: _matches.length,
        itemBuilder: (context, index) {
          final match = _matches[index];
          final int userId = match['id'] as int? ?? 0;
          final String username = match['username'] as String? ?? '';
          final int? age = match['age'] as int?;
          final String? sex = match['sex'] as String?;
          final String? bio = match['bio'] as String?;
          final int? height = match['height'] as int?;
          final String? starSign = match['star_sign'] as String?;
          final String photoUrl = '$_baseUrl/api/users/$userId/photo';

          return GestureDetector(
            onTap: () => _openChat(match),
            child: Container(
              margin: const EdgeInsets.symmetric(horizontal: 12, vertical: 6),
              decoration: BoxDecoration(
                color: const Color(0xFF1A1A1A),
                borderRadius: BorderRadius.circular(16),
              ),
              child: Padding(
                padding: const EdgeInsets.all(12),
                child: Row(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    ClipRRect(
                      borderRadius: BorderRadius.circular(12),
                      child: Image.network(
                        photoUrl,
                        width: 72,
                        height: 72,
                        fit: BoxFit.cover,
                        errorBuilder: (_, __, ___) => Container(
                          width: 72,
                          height: 72,
                          color: Colors.white12,
                          child: Center(
                            child: Text(
                              username.isNotEmpty ? username[0].toUpperCase() : '?',
                              style: const TextStyle(
                                color: Colors.white,
                                fontSize: 24,
                                fontWeight: FontWeight.bold,
                              ),
                            ),
                          ),
                        ),
                      ),
                    ),
                    const SizedBox(width: 12),
                    Expanded(
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: [
                          Row(
                            children: [
                              Expanded(
                                child: Text(
                                  username,
                                  style: const TextStyle(
                                    color: Colors.white,
                                    fontSize: 16,
                                    fontWeight: FontWeight.w600,
                                  ),
                                  overflow: TextOverflow.ellipsis,
                                ),
                              ),
                              const SizedBox(width: 8),
                              const Icon(
                                Icons.message_rounded,
                                color: Color(0xFF00C853),
                                size: 22,
                              ),
                            ],
                          ),
                          if (age != null || sex != null) ...[
                            const SizedBox(height: 2),
                            Text(
                              [if (age != null) '$age', if (sex != null) sex!].join(' · '),
                              style: const TextStyle(color: Colors.white38, fontSize: 12),
                            ),
                          ],
                          if (bio != null && bio.isNotEmpty) ...[
                            const SizedBox(height: 4),
                            Text(
                              bio,
                              style: const TextStyle(
                                color: Color(0xFFAAAAAA),
                                fontSize: 12,
                                fontStyle: FontStyle.italic,
                              ),
                              maxLines: 2,
                              overflow: TextOverflow.ellipsis,
                            ),
                          ],
                          if (height != null || starSign != null) ...[
                            const SizedBox(height: 6),
                            Wrap(
                              spacing: 6,
                              runSpacing: 4,
                              children: [
                                if (starSign != null)
                                  _MatchChip(text: starSign!),
                                if (height != null)
                                  _MatchChip(text: '$height cm'),
                              ],
                            ),
                          ],
                        ],
                      ),
                    ),
                  ],
                ),
              ),
            ),
          );
        },
      ),
    );
  }
}

class _MatchChip extends StatelessWidget {
  final String text;
  const _MatchChip({required this.text});

  @override
  Widget build(BuildContext context) {
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 3),
      decoration: BoxDecoration(
        color: const Color(0xFF2A2A2A),
        borderRadius: BorderRadius.circular(10),
        border: Border.all(color: Colors.white12, width: 0.5),
      ),
      child: Text(
        text,
        style: const TextStyle(
          color: Color(0xFFFFC107),
          fontSize: 11,
          fontWeight: FontWeight.w500,
        ),
      ),
    );
  }
}

