1	import 'package:flutter/material.dart';
2	import '../core/config.dart';
3	import '../services/api_service.dart';
4	
5	class HelloScreen extends StatefulWidget {
6	  const HelloScreen({super.key});
7	
8	  @override
9	  State<HelloScreen> createState() => _HelloScreenState();
10	}
11	
12	class _HelloScreenState extends State<HelloScreen> {
13	  bool _isLoading = true;
14	  String? _username;
15	  int? _age;
16	  String? _sex;
17	  String? _photoUrl;
18	  String? _token;
19	  String _errorMessage = '';
20	
21	  @override
22	  void initState() {
23	    super.initState();
24	    _loadProfile();
25	  }
26	
27	  Future<void> _loadProfile() async {
28	    setState(() => _isLoading = true);
29	    try {
30	      final token = await ApiService.getToken();
31	      final result = await ApiService.getProfile();
32	      if (result['success'] == true) {
33	        final data = result['data'] as Map<String, dynamic>;
34	        setState(() {
35	          _token = token;
36	          _username = data['username'] as String?;
37	          _age = data['age'] as int?;
38	          _sex = data['sex'] as String?;
39	          final rawPhotoUrl = data['photo_url'] as String?;
40	
41	          if (rawPhotoUrl != null) {
42	            _photoUrl = '${BaseConfig.baseUrl}$rawPhotoUrl';
43	          }
44	          _isLoading = false;
45	          _errorMessage = '';
46	        });
47	      } else {
48	        setState(() {
49	          _errorMessage = 'Failed to load profile';
50	          _isLoading = false;
51	        });
52	      }
53	    } catch (e) {
54	      setState(() {
55	        _errorMessage = 'Error: $e';
56	        _isLoading = false;
57	      });
58	    }
59	  }
60	
61	  Widget _buildAvatar() {
62	    if (_photoUrl != null && _token != null) {
63	      return CircleAvatar(
64	        radius: 60,
65	        backgroundColor: Colors.blueAccent.withOpacity(0.2),
66	        backgroundImage: NetworkImage(
67	          _photoUrl!,
68	          headers: {'Authorization': 'Bearer $_token'},
69	        ),
70	        onBackgroundImageError: (_, __) {},
71	        child: null,
72	      );
73	    }
74	    return CircleAvatar(
75	      radius: 60,
76	      backgroundColor: Colors.blueAccent.withOpacity(0.15),
77	      child: const Icon(Icons.person, size: 60, color: Colors.blueAccent),
