import 'package:flutter/material.dart';
import '../core/config.dart';
import '../services/api_service.dart';

class HelloScreen extends StatefulWidget {
  const HelloScreen({super.key});

  @override
  State<HelloScreen> createState() => _HelloScreenState();
}

class _HelloScreenState extends State<HelloScreen> {
  bool _isLoading = true;
  String? _username;
  int? _age;
  String? _sex;
  String? _photoUrl;
  String? _token;
  String _errorMessage = '';

  @override
  void initState() {
    super.initState();
    _loadProfile();
  }

  Future<void> _loadProfile() async {
    setState(() => _isLoading = true);
    try {
      final token = await ApiService.getToken();
      final result = await ApiService.getProfile();
      if (result['success'] == true) {
        final data = result['data'] as Map<String, dynamic>;
        setState(() {
          _token = token;
          _username = data['username'] as String?;
          _age = data['age'] as int?;
          _sex = data['sex'] as String?;
          final rawPhotoUrl = data['photo_url'] as String?;

          if (rawPhotoUrl != null) {
            _photoUrl = '${BaseConfig.baseUrl}$rawPhotoUrl';
          }
          _isLoading = false;
          _errorMessage = '';
        });
      } else {
        setState(() {
          _errorMessage = 'Failed to load profile';
          _isLoading = false;
        });
      }
    } catch (e) {
      setState(() {
        _errorMessage = 'Error: $e';
        _isLoading = false;
      });
    }
  }

  Widget _buildAvatar() {
    if (_photoUrl != null && _token != null) {
      return CircleAvatar(
        radius: 60,
        backgroundColor: Colors.blueAccent.withOpacity(0.2),
        backgroundImage: NetworkImage(
          _photoUrl!,
          headers: {'Authorization': 'Bearer $_token'},
        ),
        onBackgroundImageError: (_, __) {},
        child: null,
      );
    }
    return CircleAvatar(
      radius: 60,
      backgroundColor: Colors.blueAccent.withOpacity(0.15),
      child: const Icon(Icons.person, size: 60, color: Colors.blueAccent),
    );
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Profile'),
      ),
      body: SafeArea(
        child: Padding(
          padding: const EdgeInsets.all(28.0),
          child: _isLoading
              ? const Center(child: CircularProgressIndicator(color: Colors.blueAccent))
              : Column(
                  mainAxisAlignment: MainAxisAlignment.center,
                  children: [
                    _buildAvatar(),
                    const SizedBox(height: 24),
                    if (_username != null)
                      Text(
                        _username!,
                        style: const TextStyle(
                          fontSize: 26,
                          fontWeight: FontWeight.bold,
                          color: Colors.white,
                        ),
                      ),
                    const SizedBox(height: 12),
                    if (_age != null || _sex != null)
                      Row(
                        mainAxisAlignment: MainAxisAlignment.center,
                        children: [
                          if (_age != null) _InfoChip(label: 'Age', value: '$_age'),
                          if (_age != null && _sex != null) const SizedBox(width: 12),
                          if (_sex != null) _InfoChip(label: 'Sex', value: _sex!),
                        ],
                      ),
                    if (_errorMessage.isNotEmpty) ...[  
                      const SizedBox(height: 16),
                      Text(_errorMessage,
                          style: const TextStyle(color: Colors.redAccent),
                          textAlign: TextAlign.center),
                    ],
                    const SizedBox(height: 12),
                    const Text(
                      'You have successfully logged in!',
                      style: TextStyle(fontSize: 15, color: Colors.grey),
                      textAlign: TextAlign.center,
                    ),
                    const SizedBox(height: 48),
                    SizedBox(
                      width: double.infinity,
                      child: OutlinedButton.icon(
                        onPressed: _loadProfile,
                        icon: const Icon(Icons.refresh),
                        label: const Text('Refresh'),
                      ),
                    ),
                  ],
                ),
        ),
      ),
    );
  }
}

class _InfoChip extends StatelessWidget {
  final String label;
  final String value;
  const _InfoChip({required this.label, required this.value});

  @override
  Widget build(BuildContext context) {
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 8),
      decoration: BoxDecoration(
        color: Colors.blueAccent.withOpacity(0.15),
        borderRadius: BorderRadius.circular(20),
        border: Border.all(color: Colors.blueAccent.withOpacity(0.4)),
      ),
      child: Column(
        children: [
          Text(label,
              style: const TextStyle(fontSize: 11, color: Colors.grey)),
          Text(value,
              style: const TextStyle(
                  fontSize: 16,
                  fontWeight: FontWeight.bold,
                  color: Colors.white)),
        ],
      ),
    );
  }
}

