import 'dart:collection';
import 'dart:typed_data';
import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;
import 'package:shared_preferences/shared_preferences.dart';

class AuthedImage extends StatefulWidget {
  final String url;
  final double? width;
  final double? height;
  final BoxFit fit;
  final Widget Function(BuildContext context)? errorBuilder;
  final Widget Function(BuildContext context)? loadingBuilder;

  const AuthedImage({
    super.key,
    required this.url,
    this.width,
    this.height,
    this.fit = BoxFit.cover,
    this.errorBuilder,
    this.loadingBuilder,
  });

  @override
  State<AuthedImage> createState() => _AuthedImageState();
}

class _AuthedImageState extends State<AuthedImage> {
  static const int _cacheLimit = 50;
  static final LinkedHashMap<String, Uint8List> _cache = LinkedHashMap();

  Uint8List? _bytes;
  bool _loading = true;
  bool _error = false;

  @override
  void initState() {
    super.initState();
    _load();
  }

  @override
  void didUpdateWidget(covariant AuthedImage oldWidget) {
    super.didUpdateWidget(oldWidget);
    if (oldWidget.url != widget.url) {
      _load();
    }
  }

  Future<void> _load() async {
    final url = widget.url;

    final cached = _cache.remove(url);
    if (cached != null) {
      _cache[url] = cached;
      if (mounted) {
        setState(() {
          _bytes = cached;
          _loading = false;
          _error = false;
        });
      }
      return;
    }

    if (mounted) {
      setState(() {
        _loading = true;
        _error = false;
        _bytes = null;
      });
    }

    try {
      final prefs = await SharedPreferences.getInstance();
      final token = prefs.getString('jwt_token');
      final res = await http.get(
        Uri.parse(url),
        headers: {
          if (token != null) 'Authorization': 'Bearer $token',
        },
      );
      if (!mounted || widget.url != url) return;
      if (res.statusCode == 200) {
        final bytes = res.bodyBytes;
        _cache[url] = bytes;
        if (_cache.length > _cacheLimit) {
          _cache.remove(_cache.keys.first);
        }
        setState(() {
          _bytes = bytes;
          _loading = false;
          _error = false;
        });
      } else {
        setState(() {
          _loading = false;
          _error = true;
        });
      }
    } catch (_) {
      if (!mounted || widget.url != url) return;
      setState(() {
        _loading = false;
        _error = true;
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    if (_loading) {
      return widget.loadingBuilder?.call(context) ??
          SizedBox(width: widget.width, height: widget.height);
    }
    if (_error || _bytes == null) {
      return widget.errorBuilder?.call(context) ??
          SizedBox(width: widget.width, height: widget.height);
    }
    return Image.memory(
      _bytes!,
      width: widget.width,
      height: widget.height,
      fit: widget.fit,
      gaplessPlayback: true,
    );
  }
}

