import 'dart:convert';
import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;
import 'package:image_picker/image_picker.dart';
import '../core/config.dart';
import '../services/api_service.dart';

class GalleryScreen extends StatefulWidget {
  const GalleryScreen({super.key});

  @override
  State<GalleryScreen> createState() => _GalleryScreenState();
}

class _GalleryScreenState extends State<GalleryScreen> {
  static String get _baseUrl => BaseConfig.baseUrl;
  static const _gold = Color(0xFFFFC107);

  static const _slots = [
    {'key': 'face', 'label': 'Face Photo', 'isVideo': false},
    {'key': 'full_length', 'label': 'Full Length', 'isVideo': false},
    {'key': 'happy', 'label': 'Happy Photo', 'isVideo': false},
    {'key': 'funny', 'label': 'Funny Photo', 'isVideo': false},
    {'key': 'hobby', 'label': 'Hobby Photo', 'isVideo': false},
    {'key': 'video', 'label': '3-Second Video', 'isVideo': true},
  ];

  Map<String, String?> _mediaSlots = {};
  final Map<String, bool> _uploading = {};
  String? _token;
  int? _userId;
  bool _loading = true;

  @override
  void initState() {
    super.initState();
    _init();
  }

  Future<void> _init() async {
    _token = await ApiService.getToken();
    await _loadGallery();
  }

  Future<void> _loadGallery() async {
    try {
      final meResp = await http.get(
        Uri.parse('$_baseUrl/api/users/me'),
        headers: {'Authorization': 'Bearer $_token'},
      );
      if (meResp.statusCode == 200) {
        final data = jsonDecode(meResp.body) as Map<String, dynamic>;
        _userId = data['id'] as int?;
      }

      final resp = await http.get(
        Uri.parse('$_baseUrl/api/gallery'),
        headers: {'Authorization': 'Bearer $_token'},
      );
      if (resp.statusCode == 200) {
        final data = jsonDecode(resp.body) as Map<String, dynamic>;
        setState(() {
          _mediaSlots = data.map((k, v) => MapEntry(k, v as String?));
          _loading = false;
        });
      } else {
        setState(() => _loading = false);
      }
    } catch (_) {
      setState(() => _loading = false);
    }
  }

  Future<void> _pickAndUpload(String slot, bool isVideo) async {
    final picker = ImagePicker();
    XFile? file;

    if (isVideo) {
      file = await picker.pickVideo(source: ImageSource.gallery);
      if (file == null || !mounted) return;
      final confirmed = await _showVideoTrimDialog();
      if (!confirmed || !mounted) return;
    } else {
      file = await picker.pickImage(source: ImageSource.gallery, imageQuality: 85);
      if (file == null) return;
    }

    await _uploadFile(slot, file);
  }

  Future<bool> _showVideoTrimDialog() async {
    double start = 0.0;
    double end = 3.0;

    return await showDialog<bool>(
          context: context,
          builder: (ctx) => StatefulBuilder(
            builder: (ctx, setDlgState) => AlertDialog(
              backgroundColor: const Color(0xFF1A1A1A),
              title: const Text('Trim Video',
                  style: TextStyle(color: Colors.white, fontWeight: FontWeight.bold)),
              content: Column(
                mainAxisSize: MainAxisSize.min,
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  const Text('Select a 3-second window:',
                      style: TextStyle(color: Colors.white70, fontSize: 13)),
                  const SizedBox(height: 4),
                  const Text(
                    'Note: trimming coming soon (requires ffmpeg). Full video will be uploaded.',
                    style: TextStyle(color: Colors.white38, fontSize: 11),
                  ),
                  const SizedBox(height: 16),
                  RangeSlider(
                    values: RangeValues(start, end),
                    min: 0,
                    max: 30,
                    divisions: 60,
                    activeColor: _gold,
                    inactiveColor: Colors.white12,
                    labels: RangeLabels(
                      '${start.toStringAsFixed(1)}s',
                      '${end.toStringAsFixed(1)}s',
                    ),
                    onChanged: (v) {
                      setDlgState(() {
                        start = v.start;
                        end = (v.start + 3.0).clamp(0.0, 30.0);
                      });
                    },
                  ),
                  Text(
                    'Clip: ${start.toStringAsFixed(1)}s – ${end.toStringAsFixed(1)}s',
                    style: const TextStyle(color: Colors.white54, fontSize: 12),
                  ),
                ],
              ),
              actions: [
                TextButton(
                  onPressed: () => Navigator.pop(ctx, false),
                  child: const Text('Cancel', style: TextStyle(color: Colors.white54)),
                ),
                ElevatedButton(
                  onPressed: () => Navigator.pop(ctx, true),
                  style: ElevatedButton.styleFrom(
                    backgroundColor: _gold,
                    foregroundColor: Colors.black,
                    shape: const RoundedRectangleBorder(),
                  ),
                  child: const Text('Use this clip',
                      style: TextStyle(fontWeight: FontWeight.bold)),
                ),
              ],
            ),
          ),
        ) ??
        false;
  }

  Future<void> _uploadFile(String slot, XFile file) async {
    if (!mounted) return;
    setState(() => _uploading[slot] = true);
    try {
      final request = http.MultipartRequest(
        'POST',
        Uri.parse('$_baseUrl/api/gallery/$slot'),
      );
      request.headers['Authorization'] = 'Bearer $_token';
      request.files.add(await http.MultipartFile.fromPath('file', file.path));

      final streamed = await request.send();
      final resp = await http.Response.fromStream(streamed);

      if (resp.statusCode == 200) {
        await _loadGallery();
      } else if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(SnackBar(
          content: Text('Upload failed (${resp.statusCode})'),
          backgroundColor: Colors.redAccent,
        ));
      }
    } catch (e) {
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(SnackBar(
          content: Text('Error: $e'),
          backgroundColor: Colors.redAccent,
        ));
      }
    } finally {
      if (mounted) setState(() => _uploading[slot] = false);
    }
  }

  Future<void> _deleteMedia(String slot) async {
    final confirmed = await showDialog<bool>(
          context: context,
          builder: (ctx) => AlertDialog(
            backgroundColor: const Color(0xFF1A1A1A),
            title: const Text('Delete?', style: TextStyle(color: Colors.white)),
            content: const Text('Remove this media from your gallery?',
                style: TextStyle(color: Colors.white70)),
            actions: [
              TextButton(
                onPressed: () => Navigator.pop(ctx, false),
                child: const Text('Cancel', style: TextStyle(color: Colors.white54)),
              ),
              TextButton(
                onPressed: () => Navigator.pop(ctx, true),
                child:
                    const Text('Delete', style: TextStyle(color: Colors.redAccent)),
              ),
            ],
          ),
        ) ??
        false;

    if (!confirmed || !mounted) return;

    try {
      final resp = await http.delete(
        Uri.parse('$_baseUrl/api/gallery/$slot'),
        headers: {'Authorization': 'Bearer $_token'},
      );
      if (resp.statusCode == 200) {
        setState(() => _mediaSlots[slot] = null);
      }
    } catch (_) {}
  }

  void _showPhotoPreview(String slot, String label) {
    final url = '$_baseUrl/api/gallery/$_userId/$slot';
    showDialog(
      context: context,
      builder: (ctx) => Dialog(
        backgroundColor: Colors.black,
        insetPadding: EdgeInsets.zero,
        child: Stack(
          children: [
            Center(
              child: InteractiveViewer(
                child: Image.network(
                  url,
                  headers: {'Authorization': 'Bearer $_token'},
                  fit: BoxFit.contain,
                  errorBuilder: (_, __, ___) => const Center(
                      child: Icon(Icons.broken_image,
                          color: Colors.white38, size: 64)),
                ),
              ),
            ),
            Positioned(
              top: 16,
              right: 16,
              child: IconButton(
                onPressed: () => Navigator.pop(ctx),
                icon: const Icon(Icons.close, color: Colors.white, size: 28),
              ),
            ),
            Positioned(
              bottom: 40,
              left: 0,
              right: 0,
              child: Row(
                mainAxisAlignment: MainAxisAlignment.center,
                children: [
                  ElevatedButton.icon(
                    onPressed: () {
                      Navigator.pop(ctx);
                      final slotDef =
                          _slots.firstWhere((s) => s['key'] == slot);
                      _pickAndUpload(slot, slotDef['isVideo'] as bool);
                    },
                    icon: const Icon(Icons.swap_horiz),
                    label: const Text('Replace'),
                    style: ElevatedButton.styleFrom(
                      backgroundColor: _gold,
                      foregroundColor: Colors.black,
                      shape: const RoundedRectangleBorder(),
                    ),
                  ),
                  const SizedBox(width: 16),
                  OutlinedButton.icon(
                    onPressed: () {
                      Navigator.pop(ctx);
                      _deleteMedia(slot);
                    },
                    icon: const Icon(Icons.delete_outline,
                        color: Colors.redAccent),
                    label: const Text('Delete',
                        style: TextStyle(color: Colors.redAccent)),
                    style: OutlinedButton.styleFrom(
                      side: const BorderSide(color: Colors.redAccent),
                      shape: const RoundedRectangleBorder(),
                    ),
                  ),
                ],
              ),
            ),
          ],
        ),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: const Color(0xFF0E0E0E),
      appBar: AppBar(
        backgroundColor: const Color(0xFF0E0E0E),
        title: const Text('My Gallery'),
        iconTheme: const IconThemeData(color: Colors.white),
      ),
      body: _loading
          ? const Center(child: CircularProgressIndicator(color: _gold))
          : Padding(
              padding: const EdgeInsets.all(16),
              child: GridView.count(
                crossAxisCount: 2,
                crossAxisSpacing: 12,
                mainAxisSpacing: 12,
                childAspectRatio: 0.85,
                children: _slots.map((slot) {
                  final key = slot['key'] as String;
                  final label = slot['label'] as String;
                  final isVideo = slot['isVideo'] as bool;
                  final filled = _mediaSlots[key] != null;
                  final uploading = _uploading[key] ?? false;

                  return _SlotCard(
                    slotKey: key,
                    label: label,
                    isVideo: isVideo,
                    filled: filled,
                    uploading: uploading,
                    token: _token ?? '',
                    userId: _userId,
                    baseUrl: _baseUrl,
                    onTap: () {
                      if (uploading) return;
                      if (filled && !isVideo) {
                        _showPhotoPreview(key, label);
                      } else if (filled && isVideo) {
                        _deleteMedia(key);
                      } else {
                        _pickAndUpload(key, isVideo);
                      }
                    },
                    onDelete: () => _deleteMedia(key),
                  );
                }).toList(),
              ),
            ),
    );
  }
}


class _SlotCard extends StatelessWidget {
  final String slotKey;
  final String label;
  final bool isVideo;
  final bool filled;
  final bool uploading;
  final String token;
  final int? userId;
  final String baseUrl;
  final VoidCallback onTap;
  final VoidCallback onDelete;

  const _SlotCard({
    required this.slotKey,
    required this.label,
    required this.isVideo,
    required this.filled,
    required this.uploading,
    required this.token,
    required this.userId,
    required this.baseUrl,
    required this.onTap,
    required this.onDelete,
  });

  static const _slotIcons = <String, IconData>{
    'face': Icons.face,
    'full_length': Icons.accessibility_new,
    'happy': Icons.sentiment_satisfied,
    'funny': Icons.sentiment_very_satisfied,
    'hobby': Icons.sports_esports,
    'video': Icons.videocam,
  };

  @override
  Widget build(BuildContext context) {
    return GestureDetector(
      onTap: onTap,
      child: Container(
        color: const Color(0xFF1A1A1A),
        child: Stack(
          children: [
            if (uploading)
              const Center(
                  child: CircularProgressIndicator(color: Color(0xFFFFC107)))
            else if (filled) ...[
              if (!isVideo)
                Positioned.fill(
                  child: Image.network(
                    '$baseUrl/api/gallery/$userId/$slotKey',
                    headers: {'Authorization': 'Bearer $token'},
                    fit: BoxFit.cover,
                    errorBuilder: (_, __, ___) => const Center(
                        child: Icon(Icons.broken_image,
                            color: Colors.white38, size: 40)),
                    loadingBuilder: (ctx, child, progress) {
                      if (progress == null) return child;
                      return const Center(
                          child: CircularProgressIndicator(
                              color: Color(0xFFFFC107)));
                    },
                  ),
                )
              else
                const Positioned.fill(
                  child: Column(
                    mainAxisAlignment: MainAxisAlignment.center,
                    children: [
                      Icon(Icons.videocam,
                          color: Color(0xFFFFC107), size: 48),
                      SizedBox(height: 8),
                      Text('Video uploaded',
                          style: TextStyle(
                              color: Colors.white54, fontSize: 11)),
                    ],
                  ),
                ),
              // Delete button
              Positioned(
                top: 6,
                right: 6,
                child: GestureDetector(
                  onTap: onDelete,
                  child: Container(
                    width: 24,
                    height: 24,
                    decoration: const BoxDecoration(
                      color: Colors.red,
                      shape: BoxShape.circle,
                    ),
                    child: const Icon(Icons.close, size: 14, color: Colors.white),
                  ),
                ),
              ),
              // Label bar
              Positioned(
                bottom: 0,
                left: 0,
                right: 0,
                child: Container(
                  padding: const EdgeInsets.symmetric(vertical: 4),
                  color: Colors.black54,
                  child: Text(
                    label,
                    textAlign: TextAlign.center,
                    style: const TextStyle(
                        color: Colors.white,
                        fontSize: 11,
                        fontWeight: FontWeight.w500),
                  ),
                ),
              ),
            ] else ...[
              // Watermark background hint
              Center(
                child: Column(
                  mainAxisAlignment: MainAxisAlignment.center,
                  children: [
                    Icon(
                      _slotIcons[slotKey] ?? Icons.add_photo_alternate_outlined,
                      color: Colors.white12,
                      size: 64,
                    ),
                    const SizedBox(height: 6),
                    Padding(
                      padding: const EdgeInsets.symmetric(horizontal: 8),
                      child: Text(
                        label,
                        textAlign: TextAlign.center,
                        style: const TextStyle(
                            color: Colors.white10,
                            fontSize: 16),
                      ),
                    ),
                  ],
                ),
              ),
              Positioned.fill(child: CustomPaint(painter: _DashedBorder())),
              Center(
                child: Column(
                  mainAxisAlignment: MainAxisAlignment.center,
                  children: [
                    Icon(
                      isVideo
                          ? Icons.videocam_outlined
                          : Icons.add_photo_alternate_outlined,
                      color: Colors.white24,
                      size: 36,
                    ),
                    const SizedBox(height: 8),
                    Text(label,
                        textAlign: TextAlign.center,
                        style: const TextStyle(
                            color: Colors.white,
                            fontSize: 12,
                            fontWeight: FontWeight.w600)),
                  ],
                ),
              ),
            ],
          ],
        ),
      ),
    );
  }
}


class _DashedBorder extends CustomPainter {
  @override
  void paint(Canvas canvas, Size size) {
    final paint = Paint()
      ..color = Colors.white12
      ..strokeWidth = 1.5
      ..style = PaintingStyle.stroke;

    const dash = 8.0;
    const gap = 6.0;

    for (double x = 0; x < size.width; x += dash + gap) {
      canvas.drawLine(
          Offset(x, 0), Offset((x + dash).clamp(0, size.width), 0), paint);
      canvas.drawLine(Offset(x, size.height),
          Offset((x + dash).clamp(0, size.width), size.height), paint);
    }
    for (double y = 0; y < size.height; y += dash + gap) {
      canvas.drawLine(
          Offset(0, y), Offset(0, (y + dash).clamp(0, size.height)), paint);
      canvas.drawLine(Offset(size.width, y),
          Offset(size.width, (y + dash).clamp(0, size.height)), paint);
    }
  }

  @override
  bool shouldRepaint(_) => false;
}

